// ── Onboarding ──────────────────────────────────────────────────────

internal sealed class OnboardingSessionRepository(AiGovernanceDbContext context) : IOnboardingSessionRepository
{
    public async Task AddAsync(OnboardingSession session, CancellationToken ct)
    {
        await context.OnboardingSessions.AddAsync(session, ct);
        await context.SaveChangesAsync(ct);
    }

    public async Task<OnboardingSession?> GetByIdAsync(OnboardingSessionId id, CancellationToken ct)
        => await context.OnboardingSessions.SingleOrDefaultAsync(s => s.Id == id, ct);

    public async Task<IReadOnlyList<OnboardingSession>> ListAsync(Guid? teamId, OnboardingSessionStatus? status, CancellationToken ct)
    {
        var query = context.OnboardingSessions.AsQueryable();

        if (teamId.HasValue)
            query = query.Where(s => s.TeamId == teamId.Value);

        if (status.HasValue)
            query = query.Where(s => s.Status == status.Value);

        return await query.OrderByDescending(s => s.StartedAt).ToListAsync(ct);
    }

    public async Task UpdateAsync(OnboardingSession session, CancellationToken ct)
    {
        context.OnboardingSessions.Update(session);
        await context.SaveChangesAsync(ct);
    }
}

// ── IDE Query Sessions ──────────────────────────────────────────────

internal sealed class IdeQuerySessionRepository(AiGovernanceDbContext context) : IIdeQuerySessionRepository
{
    public async Task AddAsync(IdeQuerySession session, CancellationToken ct)
    {
        await context.IdeQuerySessions.AddAsync(session, ct);
        await context.SaveChangesAsync(ct);
    }

    public async Task<IdeQuerySession?> GetByIdAsync(IdeQuerySessionId id, CancellationToken ct)
        => await context.IdeQuerySessions.SingleOrDefaultAsync(s => s.Id == id, ct);

    public async Task<IReadOnlyList<IdeQuerySession>> ListAsync(
        string? userId, string? ideClient, IdeQuerySessionStatus? status, CancellationToken ct)
    {
        var query = context.IdeQuerySessions.AsQueryable();

        if (!string.IsNullOrWhiteSpace(userId))
            query = query.Where(s => s.UserId == userId);

        if (!string.IsNullOrWhiteSpace(ideClient))
            query = query.Where(s => s.IdeClient == ideClient);

        if (status.HasValue)
            query = query.Where(s => s.Status == status.Value);

        return await query.OrderByDescending(s => s.SubmittedAt).ToListAsync(ct);
    }

    public async Task UpdateAsync(IdeQuerySession session, CancellationToken ct)
    {
        context.IdeQuerySessions.Update(session);
        await context.SaveChangesAsync(ct);
    }
}

// ── Existing repositories ───────────────────────────────────────────
internal sealed class PromptTemplateRepository(AiGovernanceDbContext context) : IPromptTemplateRepository
{
    public async Task<PromptTemplate?> GetByIdAsync(PromptTemplateId id, CancellationToken ct)
        => await context.PromptTemplates.SingleOrDefaultAsync(t => t.Id == id, ct);

    public async Task<PromptTemplate?> GetActiveByNameAsync(string name, CancellationToken ct)
        => await context.PromptTemplates.Where(t => t.Name == name && t.IsActive).OrderByDescending(t => t.Version).FirstOrDefaultAsync(ct);

    public async Task<IReadOnlyList<PromptTemplate>> GetAllActiveAsync(CancellationToken ct)
        => await context.PromptTemplates.Where(t => t.IsActive).OrderBy(t => t.Name).ToListAsync(ct);

    public async Task<IReadOnlyList<PromptTemplate>> GetByCategoryAsync(string category, CancellationToken ct)
        => await context.PromptTemplates.Where(t => t.Category == category).OrderBy(t => t.Name).ToListAsync(ct);

    public async Task<IReadOnlyList<PromptTemplate>> GetByPersonaAsync(string persona, CancellationToken ct)
        => await context.PromptTemplates
            .Where(t => t.TargetPersonas.Contains(persona))
            .Where(t => t.IsActive)
            .OrderBy(t => t.Name)
            .ToListAsync(ct);

    public async Task<bool> ExistsByNameAsync(string name, CancellationToken ct)
        => await context.PromptTemplates.AnyAsync(t => t.Name == name, ct);

    public async Task AddAsync(PromptTemplate entity, CancellationToken ct)
    {
        await context.PromptTemplates.AddAsync(entity, ct);
        await context.SaveChangesAsync(ct);
    }
}

